{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires deriving the force law for a polymer chain under adiabatic (isentropic) conditions, which differs from the standard isothermal case. I need to separate the statistical mechanics of the chain from the thermodynamic constraints of an adiabatic process.",
  "helpers": [
    {
      "label": "statistical_mechanics_expert",
      "instructions": "Derive the partition function and the Helmholtz free energy F(T, x) for a freely jointed chain of n segments of length l extended to a total end-to-end distance x. Provide the expression for the entropy S(T, x) as a function of n, l, x, and T."
    },
    {
      "label": "thermodynamics_expert",
      "instructions": "Given the entropy S(T, x) derived by the previous helper, apply the adiabatic condition (constant entropy, dS = 0) to find the relationship between temperature T and extension x. Then, use the first law of thermodynamics or the relation for adiabatic force F = -dU/dx (where U is internal energy) or F = T(dS/dx) at constant S to derive the force law F(x)."
    }
  ],
  "synthesis_brief": "Combine the entropy expression from the first helper with the adiabatic constraint from the second helper to produce the final force law F(x). Ensure the scaling of x and the temperature dependence are correctly accounted for to match the exact coefficient and power law."
}

